// // This module performs a barrel shift operation based on the input control signals.
// - When shift_left is asserted, the data is shifted right by one bit.
// - When shift_right is asserted, the data is shifted left by one bit.
// - When rotate_right is activated, the most significant bit is moved to the least significant bit position.
// - If none of the control signals are active, the module outputs the original data unchanged.
module top_module(
    input [3:0] data,
    input shift_left,
    input shift_right,
    input rotate_right,
    output reg [3:0] shifted_data
);always @(*) begin
        if (shift_left) begin
            shifted_data = {data[2:0], 1'b0};
        end else if (shift_right) begin
            shifted_data = {1'b0, data[3:1]};
        end else if (rotate_right) begin
            shifted_data = {data[0], data[3:1]};
        end else begin
            shifted_data = data;
        end
    end

endmodule

